import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { 
  LogIn, UserPlus, ShieldCheck, FileText, CheckCircle, 
  X, LogOut, ArrowRight, Activity, Upload, Clock, HelpCircle, LayoutDashboard, Users, BarChart3, MessageCircle
} from 'lucide-react';

const Login = () => {
  // --- 1. STATE MANAGEMENT ---
  const [view, setView] = useState('landing'); 
  const [activeTab, setActiveTab] = useState('services'); 
  const [formData, setFormData] = useState({ name: '', email: '', password: '' });
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [showModal, setShowModal] = useState(false);
  const [userRequests, setUserRequests] = useState([]); 
  const [allRequests, setAllRequests] = useState([]); // All apps for Admin
  const [allUsers, setAllUsers] = useState([]); // All users for Admin Stats
  const [selectedFileName, setSelectedFileName] = useState(""); 

  // --- 2. DATA FETCHING ---
  const fetchUserRequests = async (userId) => {
    try {
      const res = await axios.get(`http://localhost:5000/api/requests/user/${userId}`);
      setUserRequests(res.data);
    } catch (err) { console.log("User fetch error"); }
  };

  const fetchAdminData = async () => {
    try {
      const [reqRes, userRes] = await Promise.all([
        axios.get('http://localhost:5000/api/requests/all'),
        axios.get('http://localhost:5000/api/users/all')
      ]);
      setAllRequests(reqRes.data); 
      setAllUsers(userRes.data);
    } catch (err) { console.log("Admin Data Fetch Error"); }
  };

  useEffect(() => {
    const token = localStorage.getItem('token');
    const role = localStorage.getItem('userRole');
    const userId = localStorage.getItem('userId');
    
    if (token) {
      setIsLoggedIn(true);
      if (role === 'admin') {
        setView('admin-dashboard');
        fetchAdminData();
      } else {
        setView('dashboard');
        if (userId) fetchUserRequests(userId);
      }
    }
  }, []);

  // --- 3. AUTHENTICATION ---
  const handleAuth = async (e) => {
    e.preventDefault();
    const mode = view === 'admin-login' ? 'login' : (view === 'register' ? 'register' : 'login');
    try {
      const res = await axios.post(`http://localhost:5000/api/auth/${mode}`, formData);
      if (mode === 'login' || view === 'admin-login') {
        localStorage.setItem('token', res.data.token);
        localStorage.setItem('userRole', res.data.user.role);
        localStorage.setItem('userId', res.data.user._id);
        localStorage.setItem('userName', res.data.user.name);
        setIsLoggedIn(true);
        if (res.data.user.role === 'admin') {
          setView('admin-dashboard');
          fetchAdminData();
        } else {
          setView('dashboard');
          fetchUserRequests(res.data.user._id);
        }
      } else {
        alert("Account Created! Please Sign In.");
        setView('login');
      }
    } catch (err) { alert("Access Denied: Invalid Credentials"); }
  };

  // --- 4. ADMIN ACTIONS ---
  const updateStatus = async (id, newStatus) => {
    try {
      await axios.put(`http://localhost:5000/api/requests/status/${id}`, { status: newStatus });
      alert(`✅ Status updated to ${newStatus}`);
      fetchAdminData(); // Refresh stats and table
    } catch (err) { alert("Update Failed"); }
  };

  // --- 5. USER ACTIONS ---
  const handleNativeUpload = async () => {
    try {
      const [fileHandle] = await window.showOpenFilePicker();
      const file = await fileHandle.getFile();
      setSelectedFileName(file.name);
    } catch (e) { console.log("Picker closed"); }
  };

  const handleCredentialSubmit = async (e) => {
    e.preventDefault();
    const requestBody = {
      userId: localStorage.getItem('userId'),
      userName: localStorage.getItem('userName'),
      type: e.target[0].value,
      licenseNumber: e.target[1].value,
      documentUrl: selectedFileName || "verification_document.pdf"
    };
    try {
      const res = await axios.post('http://localhost:5000/api/requests/submit', requestBody);
      setUserRequests([res.data.request, ...userRequests]);
      setShowModal(false);
      setSelectedFileName("");
      alert("✅ Application Submitted Successfully!");
      setActiveTab('tracking'); 
    } catch (err) { alert("Submission Failed."); }
  };

  // ==========================================
  // VIEW: LANDING / LOGIN / REGISTER
  // ==========================================
  if (view === 'landing' || view === 'login' || view === 'register' || view === 'admin-login') {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-6 text-center">
        {view === 'landing' ? (
          <div className="max-w-4xl w-full">
            <div className="mb-12">
               <div className="inline-block bg-blue-600 p-4 rounded-3xl mb-4 text-white shadow-xl shadow-blue-200"><ShieldCheck size={48} /></div>
               <h1 className="text-5xl font-black text-slate-900 tracking-tight italic uppercase">QUAD SOLUTIONS</h1>
               <p className="text-slate-500 font-medium italic">Professional Credentialing Portal</p>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              <div onClick={() => setView('register')} className="bg-white p-10 rounded-[3rem] shadow-xl border-2 border-transparent hover:border-blue-600 cursor-pointer transition text-left group">
                 <UserPlus className="text-blue-600 mb-6 group-hover:scale-110 transition" size={32} />
                 <h2 className="text-2xl font-black text-slate-800 mb-2">New Providers</h2>
                 <div className="text-blue-600 font-bold">Get Started <ArrowRight className="inline ml-2"/></div>
              </div>
              <div onClick={() => setView('login')} className="bg-slate-900 text-white p-10 rounded-[3rem] shadow-xl border-2 border-transparent hover:border-blue-400 cursor-pointer transition text-left group">
                 <LogIn className="text-blue-400 mb-6 group-hover:scale-110 transition" size={32} />
                 <h2 className="text-2xl font-black mb-2">Existing Clients</h2>
                 <div className="text-blue-400 font-bold">Sign In <ArrowRight className="inline ml-2"/></div>
              </div>
            </div>
            <footer className="mt-20 flex flex-col items-center gap-4">
                <button onClick={() => setView('admin-login')} className="flex items-center gap-2 text-slate-300 hover:text-blue-600 transition font-black uppercase text-[10px] bg-white px-6 py-2 rounded-full border border-slate-200 shadow-sm">
                    <ShieldCheck size={14}/> Internal Admin Access
                </button>
                <p className="text-slate-300 text-[10px] uppercase font-bold tracking-widest">© 2024 Quad Solutions Healthcare Systems</p>
            </footer>
          </div>
        ) : (
          <div className="w-full max-w-md bg-white p-10 rounded-[3rem] shadow-2xl relative">
            <button onClick={() => setView('landing')} className="absolute top-8 right-8 text-slate-300 hover:text-slate-600 font-bold">Back</button>
            <h2 className="text-4xl font-black mb-8 text-slate-900 italic">
                {view === 'admin-login' ? 'Secure Admin' : (view === 'login' ? 'Login' : 'Register')}
            </h2>
            <form onSubmit={handleAuth} className="space-y-4">
              {view === 'register' && <input type="text" placeholder="Full Name" className="w-full p-4 bg-slate-50 rounded-2xl outline-none font-bold" onChange={(e) => setFormData({...formData, name: e.target.value})} required />}
              <input type="email" placeholder="Email Address" className="w-full p-4 bg-slate-50 rounded-2xl outline-none font-bold" onChange={(e) => setFormData({...formData, email: e.target.value})} required />
              <input type="password" placeholder="Password" className="w-full p-4 bg-slate-50 rounded-2xl outline-none font-bold" onChange={(e) => setFormData({...formData, password: e.target.value})} required />
              <button className={`w-full py-4 rounded-2xl font-black text-lg transition shadow-xl ${view === 'admin-login' ? 'bg-slate-900 text-blue-400' : 'bg-blue-600 text-white hover:bg-blue-700'}`}>
                {view === 'admin-login' ? 'Authorize Access' : 'Continue'}
              </button>
              {view !== 'admin-login' && (
                <p onClick={() => setView(view === 'login' ? 'register' : 'login')} className="text-center text-slate-400 font-bold cursor-pointer mt-4 italic underline underline-offset-4">Switch to {view === 'login' ? 'Register' : 'Login'}</p>
              )}
            </form>
          </div>
        )}
      </div>
    );
  }

  // ==========================================
  // VIEW: ADMIN SECURE DASHBOARD (REAL DATA)
  // ==========================================
  if (view === 'admin-dashboard') {
    return (
      <div className="min-h-screen bg-slate-950 text-white flex flex-col font-sans">
        <nav className="p-6 border-b border-slate-900 flex justify-between items-center bg-black/40 backdrop-blur-xl sticky top-0 z-50">
          <div className="flex items-center gap-3"><LayoutDashboard className="text-blue-500" /><h1 className="text-xl font-black tracking-widest text-blue-500 uppercase italic">Admin Registry</h1></div>
          <button onClick={() => {localStorage.clear(); window.location.reload();}} className="bg-red-600/10 text-red-500 border border-red-500/20 px-6 py-2 rounded-xl font-black hover:bg-red-600 hover:text-white transition">Logout</button>
        </nav>
        
        <main className="p-10 max-w-7xl mx-auto w-full">
           <div className="grid grid-cols-1 md:grid-cols-3 gap-8 mb-16">
              <div className="bg-slate-900 p-10 rounded-[2.5rem] border border-slate-800 shadow-2xl relative overflow-hidden group transition">
                <Users className="absolute -right-4 -bottom-4 text-slate-800 group-hover:text-blue-600/20 transition-colors" size={120}/>
                <p className="text-slate-500 text-[10px] font-black uppercase tracking-[0.3em]">Registered Users</p>
                <h4 className="text-6xl font-black mt-2 tracking-tighter">{allUsers.length}</h4>
                <div className="mt-4 flex items-center gap-2 text-blue-500 text-[10px] font-black uppercase"><BarChart3 size={12}/> Live Database Count</div>
              </div>

              <div className="bg-slate-900 p-10 rounded-[2.5rem] border border-slate-800 border-l-4 border-l-yellow-500 shadow-2xl relative overflow-hidden group">
                <FileText className="absolute -right-4 -bottom-4 text-slate-800 group-hover:text-yellow-600/20 transition-colors" size={120}/>
                <p className="text-slate-500 text-[10px] font-black uppercase tracking-[0.3em]">Active Applications</p>
                <h4 className="text-6xl font-black mt-2 tracking-tighter text-yellow-500">{allRequests.length}</h4>
                <div className="mt-4 flex items-center gap-2 text-yellow-500 text-[10px] font-black uppercase"><Clock size={12}/> Total Service Requests</div>
              </div>

              <div className="bg-slate-900 p-10 rounded-[2.5rem] border border-slate-800 border-l-4 border-l-green-500 shadow-2xl relative overflow-hidden group">
                <CheckCircle className="absolute -right-4 -bottom-4 text-slate-800 group-hover:text-green-600/20 transition-colors" size={120}/>
                <p className="text-slate-500 text-[10px] font-black uppercase tracking-[0.3em]">Verified Status</p>
                <h4 className="text-6xl font-black mt-2 tracking-tighter text-green-500">{allRequests.filter(r => r.status === 'Approved').length}</h4>
                <div className="mt-4 flex items-center gap-2 text-green-500 text-[10px] font-black uppercase"><Activity size={12}/> Completed Verification</div>
              </div>
           </div>

           <div className="bg-slate-900/80 rounded-[3rem] border border-slate-800 shadow-2xl overflow-hidden">
              <div className="p-8 border-b border-slate-800 bg-black/20 flex justify-between items-center">
                  <h2 className="text-2xl font-black italic uppercase tracking-tighter flex items-center gap-3"><FileText className="text-blue-500"/> Provider Applications</h2>
                  <span className="text-[10px] font-black text-slate-500 uppercase bg-slate-800 px-4 py-2 rounded-xl">Real-Time Data Access</span>
              </div>
              <table className="w-full text-left">
                <thead className="bg-black/40 text-slate-500 text-[10px] font-black uppercase tracking-[0.2em] border-b border-slate-800">
                  <tr><th className="p-8">Provider Name</th><th className="p-8">Service</th><th className="p-8">Status</th><th className="p-8">Document</th><th className="p-8 text-right">Actions</th></tr>
                </thead>
                <tbody className="divide-y divide-slate-800/50">
                  {allRequests.map((req) => (
                    <tr key={req._id} className="hover:bg-blue-600/5 transition group">
                      <td className="p-8 font-black text-xs uppercase tracking-tighter">{req.userName}</td>
                      <td className="p-8 text-slate-400 font-bold text-xs uppercase italic">{req.type}</td>
                      <td className="p-8">
                        <span className={`px-4 py-1 rounded-full text-[9px] font-black uppercase tracking-widest border ${req.status === 'Approved' ? 'bg-green-500/10 text-green-500 border-green-500/20' : (req.status === 'Rejected' ? 'bg-red-500/10 text-red-500 border-red-500/20' : 'bg-yellow-500/10 text-yellow-500 border-yellow-500/20')}`}>
                            {req.status}
                        </span>
                      </td>
                      <td className="p-8 text-center text-blue-400 font-mono text-[10px] italic underline"><FileText size={16} className="mx-auto mb-1 opacity-50 group-hover:opacity-100 transition"/> {req.documentUrl}</td>
                      <td className="p-8 text-right flex justify-end gap-2">
                         <button onClick={() => updateStatus(req._id, 'Approved')} className="bg-green-600 text-white px-3 py-1 rounded-lg text-[9px] font-black uppercase hover:bg-green-500 transition">Approve</button>
                         <button onClick={() => updateStatus(req._id, 'Rejected')} className="bg-red-600/20 text-red-500 px-3 py-1 rounded-lg text-[9px] font-black uppercase border border-red-500/20 hover:bg-red-600 hover:text-white transition">Reject</button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
           </div>
        </main>
      </div>
    );
  }

  // ==========================================
  // VIEW: NORMAL USER DASHBOARD
  // ==========================================
  return (
    <div className="min-h-screen bg-slate-50 flex flex-col font-sans">
      <nav className="bg-white shadow-sm p-4 sticky top-0 z-50 border-b">
        <div className="max-w-7xl mx-auto flex justify-between items-center">
          <h1 className="text-xl font-black text-blue-600 italic">QUAD SOLUTIONS</h1>
          <div className="flex gap-4 items-center">
             <button onClick={() => setActiveTab('services')} className={`px-4 py-2 rounded-xl text-sm font-bold ${activeTab === 'services' ? 'bg-blue-600 text-white' : 'text-slate-400 hover:text-slate-600'}`}>Services</button>
             <button onClick={() => setActiveTab('tracking')} className={`px-4 py-2 rounded-xl text-sm font-bold ${activeTab === 'tracking' ? 'bg-blue-600 text-white' : 'text-slate-400'}`}>My Status</button>
             <button onClick={() => {localStorage.clear(); window.location.reload();}} className="text-red-500 font-bold px-2 hover:scale-110 transition"><LogOut size={20}/></button>
          </div>
        </div>
      </nav>

      <main className="p-10 max-w-5xl mx-auto w-full mb-20">
        {activeTab === 'services' ? (
          <section className="animate-in fade-in duration-500">
             <h2 className="text-3xl font-black text-slate-900 mb-8 tracking-tighter italic uppercase">Service Catalog</h2>
             <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                {[
                  { title: 'Medical License Renewal', icon: <FileText/> },
                  { title: 'Insurance Enrollment', icon: <Activity/> },
                  { title: 'DEA Certification', icon: <ShieldCheck/> }
                ].map((item, idx) => (
                  <div key={idx} className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100 hover:shadow-xl transition-all duration-300">
                    <div className="w-12 h-12 bg-blue-50 rounded-xl flex items-center justify-center mb-4 text-blue-600">{item.icon}</div>
                    <h3 className="text-xl font-bold mb-2 tracking-tight">{item.title}</h3>
                    <p className="text-slate-400 text-xs mb-6 font-medium leading-relaxed italic">High-speed verification for your healthcare credentials.</p>
                    <button onClick={() => setShowModal(true)} className="w-full bg-slate-900 text-white py-3 rounded-xl font-black hover:bg-blue-600 transition uppercase text-[10px] italic">Apply Now</button>
                  </div>
                ))}
             </div>
          </section>
        ) : (
          <section className="animate-in fade-in duration-500">
             <div className="flex justify-between items-end mb-8">
                <div>
                   <h2 className="text-3xl font-black text-slate-900 italic uppercase tracking-tighter underline underline-offset-8">Tracking History</h2>
                   <p className="text-slate-400 text-xs font-bold uppercase mt-2 tracking-widest">Verify your live application status</p>
                </div>
                <div className="bg-blue-600 text-white px-6 py-2 rounded-2xl text-[10px] font-black uppercase shadow-xl shadow-blue-200">{userRequests.length} Active</div>
             </div>

             <div className="space-y-4">
                {userRequests.map((req, idx) => (
                    <div key={req._id} className="bg-white rounded-[2.5rem] shadow-sm border border-slate-100 p-8 flex flex-col md:flex-row justify-between items-center hover:shadow-xl transition-all duration-300 group">
                         <div className="flex items-center gap-6 text-left">
                            <div className="w-16 h-16 bg-slate-900 rounded-3xl flex flex-col items-center justify-center text-white group-hover:bg-blue-600 transition-colors shadow-lg">
                               <span className="text-[9px] font-black opacity-40">REQ</span>
                               <span className="text-xl font-black italic">0{idx + 1}</span>
                            </div>
                            <div>
                               <h3 className="text-xl font-black text-slate-800 uppercase tracking-tighter italic">{req.type}</h3>
                               <div className="flex items-center gap-4 mt-1">
                                  <p className="text-slate-400 font-bold text-[9px] uppercase flex items-center gap-1 tracking-widest"><ShieldCheck size={12}/> {req.licenseNumber}</p>
                                  <p className="text-slate-400 font-bold text-[9px] uppercase flex items-center gap-1 tracking-widest"><Clock size={12}/> {new Date(req.submittedDate).toLocaleDateString()}</p>
                               </div>
                            </div>
                         </div>
                         <div className={`px-6 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest flex items-center gap-2 ${req.status === 'Approved' ? 'bg-green-100 text-green-600' : (req.status === 'Rejected' ? 'bg-red-100 text-red-600' : 'bg-blue-100 text-blue-600')}`}>
                             <div className={`w-2 h-2 rounded-full animate-pulse ${req.status === 'Approved' ? 'bg-green-500' : (req.status === 'Rejected' ? 'bg-red-500' : 'bg-blue-500')}`}></div>
                             {req.status}
                         </div>
                    </div>
                ))}
             </div>
          </section>
        )}
      </main>

      {/* FOOTER FOR LANDING ONLY */}
      {view === 'landing' && (
        <footer className="p-10 border-t border-slate-100 flex flex-col items-center gap-4">
            <button onClick={() => setView('admin-login')} className="flex items-center gap-2 text-slate-300 hover:text-blue-600 transition font-black uppercase text-[10px] tracking-widest bg-white px-6 py-2 rounded-full border border-slate-200">
                <ShieldCheck size={14}/> Internal Admin Access
            </button>
            <p className="text-slate-300 text-[10px] uppercase font-bold tracking-widest">© 2024 Quad Solutions Healthcare Infrastructure</p>
        </footer>
      )}

      {/* --- SUBMISSION MODAL --- */}
      {showModal && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md flex items-center justify-center p-4 z-[100]">
          <div className="bg-white w-full max-w-md rounded-[3rem] shadow-2xl p-10 animate-in zoom-in duration-200">
            <h2 className="text-2xl font-black mb-6 text-blue-600 uppercase italic underline underline-offset-8">New Submission</h2>
            <form onSubmit={handleCredentialSubmit} className="space-y-4">
              <select className="w-full p-4 bg-slate-50 rounded-2xl border-none font-bold text-slate-700 outline-none"><option>Medical License</option><option>Insurance Enrollment</option><option>DEA Certification</option></select>
              <input type="text" placeholder="License ID / NPI Number" className="w-full p-4 bg-slate-50 rounded-2xl outline-none font-bold border-none" required />
              <div onClick={handleNativeUpload} className="mt-1 p-8 bg-blue-50 rounded-2xl border-2 border-dashed border-blue-200 text-center cursor-pointer hover:bg-blue-100 transition group">
                <Upload className="mx-auto text-blue-400 mb-2 group-hover:scale-110 transition" size={28}/>
                <p className="text-[10px] font-black text-blue-600 uppercase tracking-tighter">
                   {selectedFileName ? `READY: ${selectedFileName}` : "Select Document from System"}
                </p>
              </div>
              <button className="w-full bg-blue-600 text-white py-4 rounded-2xl font-black mt-4 shadow-xl">Confirm & Submit</button>
              <button onClick={() => setShowModal(false)} type="button" className="w-full text-slate-400 font-bold text-sm">Cancel</button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Login;
